+        "ext-a",
+        Label::Secret,
+        Label::Public,
+        DeclassificationDecision::Allow,
+    );
+    let claim = confinement_claim("c1", "ext-a", ClaimStrength::Partial, 2);
+
+    idx.insert_flow_event(&ev, &ctx).unwrap();
+    idx.insert_flow_proof(&proof, &ctx).unwrap();
